-- ============================================================
-- Prewarm exercise_bank — E level (eximia cum laude).
-- Vocab: 7 topics × 2 batches = 14 batches / 56 exercises
-- Grammar: 6 topics × 2 batches = 12 batches / 48 exercises
-- Total: 26 batches / 104 exercises.
-- E-level distractors are very close in meaning — differ by register,
-- connotation, or idiomatic usage rather than basic meaning.
-- Schema: matches exercise_bank (migrations/008).
-- ============================================================

-- ─── VOCAB · E · general vocabulary ──────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'E', 'general vocabulary', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Su propuesta resultó sumamente atinada' — mitä tarkoittaa 'atinada'?","context":"Su propuesta resultó sumamente atinada y fue aceptada por unanimidad en la reunión.","options":["A) osuva","B) järkevä","C) oikeudenmukainen","D) ystävällinen"],"correct":"A","explanation":"atinado = osuva, osuvasti muotoiltu (täsmällinen). sensato = järkevä (yleinen), justo = oikeudenmukainen, amable = ystävällinen. E-tasolla nyanssit ratkaisevat."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'nitistää väitteensä' (kumota)?","context":"El profesor refutó todas sus afirmaciones con datos irrefutables.","options":["A) refutar","B) negar","C) rechazar","D) contradecir"],"correct":"A","explanation":"refutar = kumota argumentein (akateeminen). negar = kieltää (peruuttaa), rechazar = hylätä, contradecir = vastustaa sanallisesti. Kirjoitetussa akateemisessa kielessä refutar."},
  {"id":3,"type":"gap","question":"Täydennä: 'Sus palabras ___ un eco profundo en el auditorio.'","context":"Sus palabras suscitaron un eco profundo en el auditorio durante el acto académico.","options":["A) suscitaron","B) hicieron","C) causaron","D) crearon"],"correct":"A","explanation":"suscitar = herättää (tunteita, keskustelua — muodollinen). hacer/causar/crear ovat liian yleisiä akateemisessa tekstissä."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el desempeño'?","context":"El desempeño del equipo ha sido excepcional esta temporada.","options":["A) suoriutuminen","B) esiintyminen","C) voitto","D) yritys"],"correct":"A","explanation":"el desempeño = suoriutuminen (työssä/tehtävässä). la actuación = esiintyminen (taide), la victoria = voitto, el intento = yritys."}
]$json$::jsonb, 1.0),

('vocab', 'E', 'general vocabulary', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Sus argumentos resultaron endebles ante las pruebas presentadas' — mitä tarkoittaa 'endeble'?","context":"Sus argumentos resultaron endebles ante las pruebas contundentes presentadas por la defensa.","options":["A) heikko","B) väärä","C) yksinkertainen","D) vanha"],"correct":"A","explanation":"endeble = heikko, ei-uskottava (argumenteista). falso = väärä, simple = yksinkertainen, antiguo = vanha. E-tasolla 'débil' tavallinen mutta endeble nyansoidumpi."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'hahmottaa' (abstraktisti)?","context":"Cuesta vislumbrar una salida en este momento.","options":["A) vislumbrar","B) ver","C) imaginar","D) entender"],"correct":"A","explanation":"vislumbrar = hahmottaa (vaikeasti näkyvä, metaforinen). ver = nähdä, imaginar = kuvitella, entender = ymmärtää. 'Vislumbrar una salida' on kirjallinen kollokaatio."},
  {"id":3,"type":"gap","question":"Täydennä: 'El incidente ___ un interés mediático inusitado.'","context":"El incidente despertó un interés mediático inusitado durante semanas enteras.","options":["A) despertó","B) creó","C) trajo","D) llevó"],"correct":"A","explanation":"despertar interés = herättää kiinnostusta (kiinteä kollokaatio). crear/traer/llevar eivät luo yhtä voimakasta mielikuvaa."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la índole'?","context":"Se trata de un problema de índole estrictamente personal.","options":["A) luonne (asian)","B) ongelma","C) aihe","D) alue"],"correct":"A","explanation":"la índole = luonne, laatu (asian). el problema = ongelma, el tema = aihe, el área = alue. 'De índole' on muodollinen rakenne."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · E · travel and transport ────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'E', 'travel and transport', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'El turismo masificado deteriora el patrimonio' — mitä tarkoittaa 'masificado'?","context":"El turismo masificado deteriora el patrimonio histórico de las ciudades europeas.","options":["A) massoittunut","B) kansainvälinen","C) kallis","D) järjestetty"],"correct":"A","explanation":"masificado = massoittunut (liikaa ihmisiä). internacional = kansainvälinen, caro = kallis, organizado = järjestetty. Turismoon erikoistunut E-sana."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'vaikutus' (erit. ympäristöön)?","context":"El impacto del turismo en la economía local es innegable.","options":["A) el impacto","B) el efecto","C) la influencia","D) el cambio"],"correct":"A","explanation":"el impacto = vaikutus (voimakas, usein ympäristö/talous). el efecto = vaikutus (neutraali), la influencia = vaikutusvalta, el cambio = muutos."},
  {"id":3,"type":"gap","question":"Täydennä: 'Los viajeros ___ de un servicio impecable durante todo el trayecto.'","context":"Los viajeros disfrutaron de un servicio impecable durante todo el trayecto en tren.","options":["A) disfrutaron de","B) tuvieron","C) recibieron","D) consiguieron"],"correct":"A","explanation":"disfrutar de = nauttia jostakin (kohteliaan/muodollinen rekisteri). tener/recibir/conseguir ovat arkisempiä."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el trayecto'?","context":"El trayecto Madrid–Barcelona en AVE dura dos horas y media.","options":["A) matka (väli)","B) lippu","C) aikataulu","D) pysähdys"],"correct":"A","explanation":"el trayecto = matkaväli, reitti. el billete = lippu, el horario = aikataulu, la parada = pysähdys."}
]$json$::jsonb, 1.0),

('vocab', 'E', 'travel and transport', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'El auge del turismo sostenible es patente' — mitä tarkoittaa 'el auge'?","context":"El auge del turismo sostenible es patente en las cifras del último quinquenio.","options":["A) nousu","B) kiinnostus","C) muutos","D) markkinat"],"correct":"A","explanation":"el auge = nousu (voimakas kasvu). el interés = kiinnostus, el cambio = muutos, el mercado = markkinat. E-tasolla talousjournalistien vakiosana."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'kattaa' (tarpeet)?","context":"Esta oferta cubre todas las necesidades del viajero exigente.","options":["A) cubrir","B) tener","C) ofrecer","D) contener"],"correct":"A","explanation":"cubrir las necesidades = kattaa tarpeet (kollokaatio). tener/ofrecer/contener eivät muodosta yhtä täsmällistä merkitystä."},
  {"id":3,"type":"gap","question":"Täydennä: 'Las aerolíneas ___ tarifas más flexibles tras la pandemia.'","context":"Las aerolíneas han instaurado tarifas más flexibles tras la pandemia para recuperar clientes.","options":["A) han instaurado","B) han puesto","C) han dado","D) han hecho"],"correct":"A","explanation":"instaurar tarifas = ottaa käyttöön hinnasto (virallinen). poner/dar/hacer ovat liian arkisia liiketoiminnassa."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la pernoctación'?","context":"El precio incluye dos pernoctaciones en hotel de cuatro estrellas.","options":["A) yöpyminen","B) ateria","C) matka","D) vierailu"],"correct":"A","explanation":"la pernoctación = yöpyminen (virallinen matkailuterminologia). la comida = ateria, el viaje = matka, la visita = vierailu."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · E · health and body ─────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'E', 'health and body', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Hay que paliar los efectos del insomnio crónico' — mitä tarkoittaa 'paliar'?","context":"Hay que paliar los efectos del insomnio crónico mediante técnicas de relajación.","options":["A) lieventää","B) parantaa","C) ehkäistä","D) analysoida"],"correct":"A","explanation":"paliar = lieventää (oireita, ei paranna). curar = parantaa (täysin), prevenir = ehkäistä, analizar = analysoida. Lääketieteellisessä kielessä paliar."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'parantumaton' (sairaus)?","context":"Se trata de una enfermedad incurable pero se puede controlar.","options":["A) incurable","B) grave","C) crónico","D) permanente"],"correct":"A","explanation":"incurable = parantumaton. grave = vakava, crónico = krooninen (pitkäaikainen mutta voi parantua), permanente = pysyvä. Niiden väliset nyanssit E-tasolla."},
  {"id":3,"type":"gap","question":"Täydennä: 'Los hábitos saludables ___ una vida más plena.'","context":"Los hábitos saludables propician una vida más plena y satisfactoria.","options":["A) propician","B) hacen","C) dan","D) traen"],"correct":"A","explanation":"propiciar = edistää, suosia (saada aikaan suotuisia olosuhteita). hacer/dar/traer eivät vastaa sävyä."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el desgaste'?","context":"El desgaste físico tras la competición fue considerable.","options":["A) kuluminen","B) väsymys","C) loukkaantuminen","D) kipu"],"correct":"A","explanation":"el desgaste = kuluminen (fyysinen/henkinen kuormitus). el cansancio = väsymys (lievempi), la lesión = loukkaantuminen, el dolor = kipu."}
]$json$::jsonb, 1.0),

('vocab', 'E', 'health and body', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Los tratamientos paliativos mejoran la calidad de vida' — mitä tarkoittaa 'paliativo'?","context":"Los tratamientos paliativos mejoran la calidad de vida de los pacientes terminales.","options":["A) oireita lievittävä","B) parantava","C) ennaltaehkäisevä","D) kuntouttava"],"correct":"A","explanation":"paliativo = oireita lievittävä (ei paranna). curativo = parantava, preventivo = ennaltaehkäisevä, rehabilitador = kuntouttava."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'väsymys' (pitkäaikainen, voimakas)?","context":"Sufría un agotamiento extremo por el exceso de trabajo.","options":["A) el agotamiento","B) el cansancio","C) la fatiga","D) el sueño"],"correct":"A","explanation":"el agotamiento = uupumus (äärimmäinen). el cansancio = väsymys (normaali), la fatiga = fatiikki (lääketiet.), el sueño = unisuus."},
  {"id":3,"type":"gap","question":"Täydennä: 'La medicina preventiva ___ muchas patologías.'","context":"La medicina preventiva evita muchas patologías graves en fases tempranas.","options":["A) evita","B) quita","C) rompe","D) pierde"],"correct":"A","explanation":"evitar patologías = välttää sairaudet (muodollinen). quitar/romper/perder eivät sovi sairauskontekstiin."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la afección'?","context":"Presenta una afección cardíaca que requiere seguimiento constante.","options":["A) vaiva","B) tunne","C) rakkaus","D) vaikutus"],"correct":"A","explanation":"la afección = vaiva, sairaus (lääket.). VAROITUS: 'afecto' = kiintymys, 'afectar' = vaikuttaa — false friend -vaara E-tasolla."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · E · society and politics ────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'E', 'society and politics', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'La ciudadanía exige transparencia' — mitä tarkoittaa 'la ciudadanía'?","context":"La ciudadanía exige transparencia total en la gestión de los fondos públicos.","options":["A) kansalaisyhteiskunta","B) kaupunki","C) yhteisö","D) julkisuus"],"correct":"A","explanation":"la ciudadanía = kansalaisyhteiskunta, kansalaiset kollektiivina. la ciudad = kaupunki, la comunidad = yhteisö, la publicidad = julkisuus/mainonta."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'vaarantaa' (vakava)?","context":"Esas decisiones podrían vulnerar derechos fundamentales.","options":["A) vulnerar","B) romper","C) herir","D) dañar"],"correct":"A","explanation":"vulnerar derechos = loukata/vaarantaa oikeuksia (juridinen). romper = rikkoa (konkreettinen), herir = haavoittaa, dañar = vahingoittaa. Juridisessa rekisterissä vulnerar."},
  {"id":3,"type":"gap","question":"Täydennä: 'El debate ___ la necesidad de una reforma estructural.'","context":"El debate puso de manifiesto la necesidad de una reforma estructural profunda.","options":["A) puso de manifiesto","B) mostró","C) enseñó","D) dijo"],"correct":"A","explanation":"poner de manifiesto = tuoda esiin, paljastaa (muodollinen ilmaus). mostrar/enseñar/decir eivät vastaa sävyä."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el hito'?","context":"Las elecciones marcaron un hito en la historia democrática del país.","options":["A) virstanpylväs","B) päivä","C) vaalit","D) muutos"],"correct":"A","explanation":"el hito = virstanpylväs (historiallinen merkkipaalu). el día = päivä, las elecciones = vaalit, el cambio = muutos."}
]$json$::jsonb, 1.0),

('vocab', 'E', 'society and politics', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'El gobierno se ha visto instado a dimitir' — mitä tarkoittaa 'instar'?","context":"El gobierno se ha visto instado a dimitir tras el escándalo de corrupción.","options":["A) kehottaa painokkaasti","B) pyytää","C) auttaa","D) puolustaa"],"correct":"A","explanation":"instar = kehottaa painokkaasti (muodollinen, usein vaatia). pedir = pyytää (lievempi), ayudar = auttaa, defender = puolustaa."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'epäkohta' (yhteiskunnallinen)?","context":"Hay que denunciar las injusticias que afectan a los colectivos vulnerables.","options":["A) la injusticia","B) el problema","C) la diferencia","D) la dificultad"],"correct":"A","explanation":"la injusticia = epäoikeudenmukaisuus, epäkohta. el problema = ongelma (yleinen), la diferencia = ero, la dificultad = vaikeus."},
  {"id":3,"type":"gap","question":"Täydennä: 'La nueva ley ___ los derechos de los trabajadores migrantes.'","context":"La nueva ley salvaguarda los derechos de los trabajadores migrantes en situación vulnerable.","options":["A) salvaguarda","B) guarda","C) cuida","D) protege"],"correct":"A","explanation":"salvaguardar = varjella (virallinen, juridinen). guardar = säilyttää (konkreettinen), cuidar = hoitaa, proteger = suojella (neutraali). Juridisessa kielessä salvaguardar."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la injerencia'?","context":"El informe denuncia la injerencia extranjera en las elecciones.","options":["A) puuttuminen","B) tutkimus","C) neuvottelu","D) tuki"],"correct":"A","explanation":"la injerencia = puuttuminen (ei-toivottu). la investigación = tutkimus, la negociación = neuvottelu, el apoyo = tuki."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · E · environment and nature ──────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'E', 'environment and nature', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Los ecosistemas marinos se ven mermados por la sobrepesca' — mitä tarkoittaa 'mermar'?","context":"Los ecosistemas marinos se ven mermados drásticamente por la sobrepesca industrial.","options":["A) vähentää","B) tuhota","C) muuttaa","D) rikkoa"],"correct":"A","explanation":"mermar = vähentää (asteittain). destruir = tuhota (täysin), cambiar = muuttaa, romper = rikkoa. E-tasolla 'mermar' viittaa resurssien vähenemiseen."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'hupeneva' (resurssit)?","context":"Los recursos menguantes nos obligan a cambiar de modelo.","options":["A) menguante","B) poco","C) pequeño","D) escaso"],"correct":"A","explanation":"menguante = hupeneva (dynaaminen, aktiivisesti vähenevä). poco = vähän, pequeño = pieni, escaso = niukka (staattinen tila)."},
  {"id":3,"type":"gap","question":"Täydennä: 'La biodiversidad ___ un declive preocupante.'","context":"La biodiversidad experimenta un declive preocupante desde hace décadas.","options":["A) experimenta","B) hace","C) tiene","D) ve"],"correct":"A","explanation":"experimentar un declive = kokea lasku (muodollinen, tieteellinen). hacer/tener/ver ovat liian arkisia biologian diskurssissa."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la sobreexplotación'?","context":"La sobreexplotación de los acuíferos pone en riesgo el suministro de agua.","options":["A) ylikuormitus","B) käyttö","C) hyödyntäminen","D) tuhlaus"],"correct":"A","explanation":"la sobreexplotación = liikakäyttö, ylikuormitus. el uso = käyttö (neutraali), el aprovechamiento = hyödyntäminen, el despilfarro = tuhlaus."}
]$json$::jsonb, 1.0),

('vocab', 'E', 'environment and nature', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Hay que atajar la deforestación con medidas urgentes' — mitä tarkoittaa 'atajar'?","context":"Hay que atajar la deforestación con medidas urgentes y coordinadas a nivel global.","options":["A) pysäyttää","B) hidastaa","C) tutkia","D) estää"],"correct":"A","explanation":"atajar = pysäyttää, leikata poikki (ongelma). ralentizar = hidastaa, investigar = tutkia, impedir = estää (ennakolta)."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'järkyttää' (tasapainoa)?","context":"El cambio climático perturba los ecosistemas más frágiles.","options":["A) perturbar","B) cambiar","C) mover","D) afectar"],"correct":"A","explanation":"perturbar = järkyttää (tasapainoa). cambiar = muuttaa, mover = liikuttaa, afectar = vaikuttaa (neutraali). Tieteellisessä kielessä perturbar."},
  {"id":3,"type":"gap","question":"Täydennä: 'Las políticas medioambientales ___ una revisión profunda.'","context":"Las políticas medioambientales requieren una revisión profunda y urgente.","options":["A) requieren","B) quieren","C) piden","D) buscan"],"correct":"A","explanation":"requerir = vaatia (muodollinen, asioista). querer/pedir/buscar ovat aktiivisia tekijöitä — eivät sovi abstrakteille politiikoille E-tasolla."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la merma'?","context":"La merma de especies autóctonas es un problema ecológico grave.","options":["A) väheneminen","B) kasvu","C) muutos","D) siirtyminen"],"correct":"A","explanation":"la merma = väheneminen (aktiivinen menetys). el crecimiento = kasvu (vastakohta), el cambio = muutos, la migración = siirtyminen."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · E · culture and arts ────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'E', 'culture and arts', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'La obra rezuma originalidad en cada página' — mitä tarkoittaa 'rezumar'?","context":"La obra rezuma originalidad en cada página y sorprende al lector constantemente.","options":["A) huokua","B) näyttää","C) sisältää","D) olla"],"correct":"A","explanation":"rezumar = huokua, tihkua (luonne ulospäin). mostrar = näyttää (aktiivinen), contener = sisältää, ser = olla. 'Rezumar' on kirjallinen metafora."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'lumoava' (taideteos)?","context":"Es una obra cautivadora que atrapa desde la primera escena.","options":["A) cautivador","B) interesante","C) bonito","D) emocionante"],"correct":"A","explanation":"cautivador = lumoava (intensiivinen). interesante = mielenkiintoinen (neutraali), bonito = kaunis, emocionante = tunteisiin vetoava."},
  {"id":3,"type":"gap","question":"Täydennä: 'El escritor ___ un universo literario propio.'","context":"El escritor ha forjado un universo literario propio a lo largo de décadas.","options":["A) ha forjado","B) ha hecho","C) ha creado","D) ha escrito"],"correct":"A","explanation":"forjar un universo = takoa, luoda ajan kanssa (voimakas metafora). hacer/crear/escribir ovat neutraaleja — forjar kantaa taiteellista painoa."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la trama'?","context":"La trama de la novela es intrincada pero absolutamente coherente.","options":["A) juoni","B) hahmot","C) tunnelma","D) tyyli"],"correct":"A","explanation":"la trama = juoni (kirjallinen). los personajes = hahmot, la atmósfera = tunnelma, el estilo = tyyli."}
]$json$::jsonb, 1.0),

('vocab', 'E', 'culture and arts', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Su obra tardía se caracteriza por un marcado pesimismo' — mitä tarkoittaa 'tardío'?","context":"Su obra tardía se caracteriza por un marcado pesimismo y una introspección profunda.","options":["A) myöhäinen (tuotantokausi)","B) viimeinen","C) hidas","D) myöhästynyt"],"correct":"A","explanation":"tardío = myöhäinen (uratason kausi). último = viimeinen (kronologisesti), lento = hidas, retrasado = myöhästynyt. Taidehistorian 'obra tardía' on vakiintunut termi."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'päättää' (taiteellisesti muotoilla)?","context":"El artista plasmó sus ideas en una serie de esculturas monumentales.","options":["A) plasmar","B) hacer","C) mostrar","D) explicar"],"correct":"A","explanation":"plasmar = ilmentää, muotoilla konkreettiseksi. hacer = tehdä (yleinen), mostrar = näyttää, explicar = selittää. 'Plasmar ideas' on taidekollokaatio."},
  {"id":3,"type":"gap","question":"Täydennä: 'La película ___ una reflexión aguda sobre la identidad.'","context":"La película ofrece una reflexión aguda sobre la identidad cultural contemporánea.","options":["A) ofrece","B) da","C) hace","D) tiene"],"correct":"A","explanation":"ofrecer una reflexión = tarjota pohdinta (kriittinen kollokaatio). dar/hacer/tener eivät sovi kriitikkokieleen."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el legado'?","context":"El legado cultural de esta generación sigue vivo tres décadas después.","options":["A) perintö","B) teos","C) tyyli","D) muisto"],"correct":"A","explanation":"el legado = perintö (kulttuurinen). la obra = teos, el estilo = tyyli, el recuerdo = muisto."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · E · work and economy ────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'E', 'work and economy', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'La empresa acusa una caída notable de ingresos' — mitä tarkoittaa 'acusar'?","context":"La empresa acusa una caída notable de ingresos en el último trimestre fiscal.","options":["A) osoittaa (kokea)","B) syyttää","C) kieltää","D) pelätä"],"correct":"A","explanation":"acusar (talouskieli) = osoittaa, kokea (esim. laskua). VAROITUS: yleensä 'acusar' = syyttää — rekisteri muuttaa merkityksen. E-tasolla tämä nyanssi."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'kasvattaa' (pääomaa)?","context":"La firma incrementó su capital un quince por ciento.","options":["A) incrementar","B) subir","C) crecer","D) aumentar"],"correct":"A","explanation":"incrementar = kasvattaa (virallinen, yritysviestintä). subir = nousta (arki), crecer = kasvaa (intransitiivinen), aumentar = lisätä (yleisempi). Raporteissa incrementar."},
  {"id":3,"type":"gap","question":"Täydennä: 'El mercado laboral ___ signos de recuperación.'","context":"El mercado laboral muestra signos claros de recuperación tras la crisis.","options":["A) muestra","B) da","C) tiene","D) hace"],"correct":"A","explanation":"mostrar signos = näyttää merkkejä (talouskollokaatio). dar/tener/hacer signos eivät ole standardeja taloustekstissä."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la desaceleración'?","context":"La desaceleración económica preocupa a los analistas financieros.","options":["A) kasvun hidastuminen","B) lama","C) kriisi","D) muutos"],"correct":"A","explanation":"la desaceleración = (kasvun) hidastuminen. la recesión = lama, la crisis = kriisi, el cambio = muutos. Hieno nyanssi E-tasolla."}
]$json$::jsonb, 1.0),

('vocab', 'E', 'work and economy', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Las empresas multinacionales eluden el pago de impuestos' — mitä tarkoittaa 'eludir'?","context":"Las empresas multinacionales eluden el pago de impuestos mediante paraísos fiscales.","options":["A) kiertää (laillisesti)","B) vältellä","C) kieltäytyä","D) lopettaa"],"correct":"A","explanation":"eludir impuestos = kiertää veroja (lain puitteissa; eri kuin 'evadir' joka on rikos). evitar = välttää, rehusar = kieltäytyä, parar = lopettaa."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'palkkaero'?","context":"La brecha salarial entre géneros persiste pese a las leyes vigentes.","options":["A) la brecha salarial","B) la diferencia","C) el problema","D) el conflicto"],"correct":"A","explanation":"la brecha salarial = palkkakuilu (vakiintunut termi). la diferencia = ero (neutraali), el problema = ongelma, el conflicto = konflikti."},
  {"id":3,"type":"gap","question":"Täydennä: 'El sector tecnológico ___ un crecimiento exponencial.'","context":"El sector tecnológico registra un crecimiento exponencial en los últimos años.","options":["A) registra","B) tiene","C) ve","D) hace"],"correct":"A","explanation":"registrar crecimiento = kirjata kasvu (tilastollinen, muodollinen). tener/ver/hacer ovat arkisempia."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la coyuntura'?","context":"La coyuntura económica actual exige cautela en las inversiones.","options":["A) suhdanne","B) markkinat","C) talous","D) tilanne"],"correct":"A","explanation":"la coyuntura = suhdanne, taloudellinen tilannekuva. el mercado = markkinat, la economía = talous, la situación = tilanne (liian yleinen)."}
]$json$::jsonb, 1.0);

